import{_ as t,o,c as r,a0 as e}from"./chunks/framework.Bogozrur.js";const d=JSON.parse('{"title":"朝鉴 · 荆州早报","description":"","frontmatter":{"title":"2026-06-04T00:00:00.000Z","date":"2026-06-04T00:00:00.000Z","categories":["chaojian"],"tags":["朝鉴","趋势洞察","新闻","经济"],"author":"银枢局"},"headers":[],"relativePath":"posts/chaojian/chaojian-2026-06-04.md","filePath":"posts/chaojian/chaojian-2026-06-04.md"}'),n={name:"posts/chaojian/chaojian-2026-06-04.md"};function p(s,a,i,l,h,c){return o(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="朝鉴-·-荆州早报" tabindex="-1">朝鉴 · 荆州早报 <a class="header-anchor" href="#朝鉴-·-荆州早报" aria-label="Permalink to &quot;朝鉴 · 荆州早报&quot;">​</a></h1><p><strong>2026年6月4日 星期四 | 农历丙午年四月十九</strong></p><hr><hr><h2 id="🔥-今日头条" tabindex="-1">🔥 今日头条 <a class="header-anchor" href="#🔥-今日头条" aria-label="Permalink to &quot;🔥 今日头条&quot;">​</a></h2><p><strong>1. 荆州全城护航高考！4.2万考生本周日出征</strong></p><p>6月7日起，荆州4.2万名考生将走进高考考场。荆州多部门精准施策：交警对考点周边道路实施临时交通管制（6月7-9日），听力考试期间部分路段禁止通行、禁止鸣笛。全城暖心护航，为青春让路。</p><p><strong>2. 荆州经开区：绿色智造筑就千亿产业新城</strong></p><p>湖北日报专版聚焦荆州经开区——美的冰箱荆州工厂入选全球&quot;灯塔工厂&quot;，核心组装工序仅需13秒；6兆瓦分布式光伏年减碳3768吨，绿电占比40%；法雷奥实现荆州绿色供应链领域&quot;零的突破&quot;。生态底色正在夯实高质量发展。</p><h2 id="📢-政务动态" tabindex="-1">📢 政务动态 <a class="header-anchor" href="#📢-政务动态" aria-label="Permalink to &quot;📢 政务动态&quot;">​</a></h2><p><strong>3. 市委首次政党协商座谈会召开，聚焦新兴产业布局</strong></p><p>6月2日，市长李迎伟出席2026年市委第一次政党协商座谈会，主题&quot;加快布局新兴产业、未来产业，推动荆州经济转型发展&quot;，各民主党派、工商联及无党派人士建言献策。</p><p><strong>4. 湖北水发集团与荆州市政府签署战略合作协议</strong></p><p>6月2日签约，双方围绕重大水利基础设施、城乡供排水一体化、灌区现代化改造、洪湖流域水生态治理等领域深化合作，开启荆州水利高质量发展新篇章。</p><p><strong>5. 能特科技：从被动搬迁到主动逐绿的十年蝶变</strong></p><p>湖北日报头版关注。2018年沿江化工企业&quot;关改搬转&quot;启动以来，能特科技从荆州开发区老厂区搬入化工新材料产业园，完成从被动搬迁到主动转型升级的华丽转身，成为长江大保护的荆州样本。</p><h2 id="🏙-民生关注" tabindex="-1">🏙 民生关注 <a class="header-anchor" href="#🏙-民生关注" aria-label="Permalink to &quot;🏙 民生关注&quot;">​</a></h2><p><strong>6. 2026年荆州中考招生方案出炉，三大变化引人注目</strong></p><p>普高志愿设置从三批次变四批次；沙市中学和荆州中学仍分区域招生；其他学校面向全市县市招生。考生家长需重点关注志愿填报新规。</p><p><strong>7. 荆州殡葬新政：基本殡葬费用&quot;一站式&quot;直接免除</strong></p><p>免除对象从中心城区居民大幅扩大——荆州市户籍火化人员、在荆州辖区内火化的非户籍人员、异地死亡火化的荆州户籍人员均可享受，真正实现惠民殡葬全覆盖。</p><p><strong>8. 荆州动物园即将重装开园！新成员与亮点揭秘</strong></p><p>沙市中山公园动物园改造升级工程进入尾声，新动物成员和互动体验即将亮相，市民期待已久的城市动物园即将焕新回归。</p><h2 id="🌦-天气与服务" tabindex="-1">🌦 天气与服务 <a class="header-anchor" href="#🌦-天气与服务" aria-label="Permalink to &quot;🌦 天气与服务&quot;">​</a></h2><p><strong>9. 荆州6月气候预测：气温略偏高，降水偏多需防暴雨</strong></p><p>预计6月气温26~27℃，较常年偏高0.4~0.6℃；降水180~250毫米，略偏多。主要降水过程出现在5-8日、15-16日、18-20日、22-24日、28-29日，需防范暴雨强对流天气。</p><p><strong>10. 荆州市直事业单位2026年招聘：体检考察6月26日前完成</strong></p><p>综合成绩已公布，体检参照公务员录用标准执行，考生请保持联系方式畅通，等待各招聘单位具体通知。</p><hr><h2 id="📋-一句话速览" tabindex="-1">📋 一句话速览 <a class="header-anchor" href="#📋-一句话速览" aria-label="Permalink to &quot;📋 一句话速览&quot;">​</a></h2><ul><li>🏗 荆州智慧制造产业园总投资8.26亿，预计本月交付，可容纳30家企业</li><li>🤝 张青松率队赴湖南招商，精准对接优质产业资源</li><li>🏫 荆州市赴扬州专题考察学习圆满完成</li><li>⚖️ 石首市人大常委会副主任曾荣接受审查调查</li><li>🏗 荆州经开区东方大道与曙光路路口联通工程竣工投用</li></ul><hr><blockquote><p>📰 信息来源：荆州新闻网、湖北日报、荆楚网、荆州市政府官网</p><p><em>朝鉴 · 每天早7点，读懂荆州</em></p></blockquote>',33)])])}const g=t(n,[["render",p]]);export{d as __pageData,g as default};
